import{_ as t,o as d,c as o,a3 as a}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Central API v1","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Central API v1 | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/api/central-v1"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Central API v1 | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/api/central-v1"}]]},"headers":[],"relativePath":"api/central-v1.md","filePath":"api/central-v1.md","lastUpdated":1784746021000}'),c={name:"api/central-v1.md"};function s(r,e,i,n,l,p){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="central-api-v1" tabindex="-1">Central API v1 <a class="header-anchor" href="#central-api-v1" aria-label="Permalink to &quot;Central API v1&quot;">​</a></h1><p>Base path: <code>/api/central/v1</code></p><p>Auth: Sanctum bearer token, guard <code>central-api</code>.</p><p>Authorization: Spatie permissions + policies. The <code>superadmin</code> role bypasses all gates.</p><p>Response envelope on every endpoint:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;success&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { } </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;meta&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { } </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p>Paginated list endpoints populate <code>meta</code> (<code>current_page</code>, <code>last_page</code>, <code>per_page</code>, <code>total</code>, <code>next_page_url</code>, <code>prev_page_url</code>); single-resource endpoints set <code>meta: null</code>.</p><h2 id="auth-profile" tabindex="-1">Auth &amp; profile <a class="header-anchor" href="#auth-profile" aria-label="Permalink to &quot;Auth &amp; profile&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Notes</th></tr></thead><tbody><tr><td>POST</td><td><code>/auth/login</code></td><td>Throttled (<code>throttle:auth-login</code>, 5/min by email or IP)</td></tr><tr><td>POST</td><td><code>/auth/forgot-password</code></td><td></td></tr><tr><td>POST</td><td><code>/auth/reset-password</code></td><td>Body: <code>email</code>, <code>token</code>, <code>password</code>, <code>password_confirmation</code></td></tr><tr><td>GET</td><td><code>/me</code></td><td>Current user + roles/permissions</td></tr><tr><td>POST</td><td><code>/me</code></td><td>Update profile</td></tr><tr><td>POST</td><td><code>/me/change-password</code></td><td></td></tr><tr><td>POST</td><td><code>/me/logout</code></td><td>Revokes tokens</td></tr><tr><td>GET</td><td><code>/dashboard</code></td><td>Platform stats — permission <code>dashboard.view</code>; see <a href="#dashboard-payload">Dashboard payload</a></td></tr></tbody></table><h2 id="platform" tabindex="-1">Platform <a class="header-anchor" href="#platform" aria-label="Permalink to &quot;Platform&quot;">​</a></h2><h3 id="tenants" tabindex="-1">Tenants <a class="header-anchor" href="#tenants" aria-label="Permalink to &quot;Tenants&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Permission</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/tenants</code></td><td><code>tenants.list</code></td><td></td></tr><tr><td>POST</td><td><code>/tenants</code></td><td><code>tenants.create</code></td><td>Provisions default modules — see <a href="/developer-guide/tenant-provisioning">tenant provisioning</a></td></tr><tr><td>GET</td><td><code>/tenants/{tenant}</code></td><td><code>tenants.read</code></td><td>Includes <code>installed_modules</code> when loaded</td></tr><tr><td>PUT/PATCH</td><td><code>/tenants/{tenant}</code></td><td><code>tenants.update</code></td><td></td></tr><tr><td>DELETE</td><td><code>/tenants/{tenant}</code></td><td><code>tenants.delete</code></td><td>Soft delete</td></tr><tr><td>POST</td><td><code>/tenants/{tenant}/restore</code></td><td><code>tenants.restore</code></td><td>Also restores the tenant&#39;s soft-deleted users and domains</td></tr><tr><td>DELETE</td><td><code>/tenants/{tenant}/force</code></td><td><code>tenants.force.delete</code></td><td>Force-deletes users, domains, module subscriptions, then the tenant</td></tr><tr><td>POST</td><td><code>/tenants/{tenant}/archive</code></td><td><code>tenants.archive</code></td><td>Sets <code>archived_at</code>; independent of soft delete</td></tr><tr><td>POST</td><td><code>/tenants/{tenant}/unarchive</code></td><td><code>tenants.archive</code></td><td>Clears <code>archived_at</code></td></tr><tr><td>GET</td><td><code>/tenants/{tenant}/entitlements</code></td><td><code>tenants.read</code></td><td><code>{ core, modules }</code> — licensing only</td></tr><tr><td>POST</td><td><code>/tenants/{tenant}/modules</code></td><td><code>module-subscriptions.create</code></td><td>Install module — body: <code>module_id</code>, optional <code>billing_cycle</code></td></tr><tr><td>GET</td><td><code>/tenants/{tenant}/invoices</code></td><td><code>invoices.list</code></td><td>Paginated workspace invoices</td></tr><tr><td>GET</td><td><code>/tenants/{tenant}/payments</code></td><td><code>payments.list</code></td><td>Paginated workspace payments</td></tr><tr><td>POST</td><td><code>/tenants/{tenant}/impersonate</code></td><td><code>impersonation.start</code></td><td>Body: <code>reason</code> (required, 5–1000 chars)</td></tr></tbody></table><p>Tenant create/update body: <code>company_name</code>, <code>workspace_name?</code>, <code>slug?</code>, <code>email</code>, <code>phone?</code>, <code>logo?</code> (image upload), <code>notes?</code>, <code>domain?</code>, <code>status?</code>, <code>timezone?</code>, <code>currency?</code>, <code>country?</code>, <code>locale?</code>. Multipart form-data is supported for logo uploads. Response includes <code>logo_path</code> and <code>logo_url</code>.</p><h3 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Permission</th><th>Notes</th></tr></thead><tbody><tr><td>POST</td><td><code>/users/invite</code></td><td><code>users.invite</code></td><td>Creates the user, assigns roles, emails an invite, sets <code>invite_token</code>/<code>invite_sent_at</code></td></tr><tr><td>GET</td><td><code>/users</code></td><td><code>users.list</code></td><td></td></tr><tr><td>POST</td><td><code>/users</code></td><td><code>users.create</code></td><td></td></tr><tr><td>GET</td><td><code>/users/{user}</code></td><td><code>users.read</code> (or self)</td><td></td></tr><tr><td>PUT/PATCH</td><td><code>/users/{user}</code></td><td><code>users.update</code></td><td></td></tr><tr><td>DELETE</td><td><code>/users/{user}</code></td><td><code>users.delete</code></td><td></td></tr><tr><td>POST</td><td><code>/users/{user}/restore</code></td><td><code>users.restore</code></td><td></td></tr><tr><td>DELETE</td><td><code>/users/{user}/force</code></td><td><code>users.force.delete</code></td><td></td></tr><tr><td>POST</td><td><code>/users/{user}/suspend</code></td><td><code>users.suspend</code></td><td></td></tr><tr><td>POST</td><td><code>/users/{user}/unsuspend</code></td><td><code>users.unsuspend</code></td><td></td></tr><tr><td>POST</td><td><code>/users/{user}/change-password</code></td><td><code>users.reset-password</code></td><td></td></tr><tr><td>GET</td><td><code>/users/{user}/activity</code></td><td><code>users.read</code> (or self)</td><td>Up to 50 recent <code>spatie/laravel-activitylog</code> entries for the user</td></tr></tbody></table><p>Invite body: <code>name</code>, <code>email</code>, <code>phone?</code>, <code>role[]</code> (role names, at least one).</p><p>Create/update body adds: <code>phone?</code>, <code>avatar_path?</code>, <code>password</code> (create), <code>role[]</code>.</p><h3 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Permission</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/roles/permissions-matrix</code></td><td><code>roles.list</code></td><td>All permissions grouped by prefix, with the list of role names holding each one</td></tr><tr><td>GET</td><td><code>/roles</code></td><td><code>roles.list</code></td><td></td></tr><tr><td>POST</td><td><code>/roles</code></td><td><code>roles.create</code></td><td></td></tr><tr><td>GET</td><td><code>/roles/{role}</code></td><td><code>roles.read</code></td><td>Returns the role plus every permission with an <code>is_assigned</code> flag</td></tr><tr><td>PUT/PATCH</td><td><code>/roles/{role}</code></td><td><code>roles.update</code></td><td>Body: <code>name</code>, <code>permissions[]</code> (permission IDs)</td></tr><tr><td>DELETE</td><td><code>/roles/{role}</code></td><td><code>roles.delete</code></td><td>Blocked for protected roles (<code>config(&#39;central-protected-roles&#39;)</code>)</td></tr><tr><td>POST</td><td><code>/roles/{role}/clone</code></td><td><code>roles.clone</code></td><td>Copies all permissions to a new role; optional <code>name</code> in body, otherwise auto-generated</td></tr></tbody></table><p><code>permissions-matrix</code> response shape: <code>[{ &quot;id&quot;, &quot;name&quot;, &quot;group&quot;, &quot;roles&quot;: [&quot;admin&quot;, &quot;manager&quot;, ...] }]</code>, where <code>group</code> is the permission name&#39;s prefix before the first <code>.</code> (e.g. <code>tenants</code> for <code>tenants.archive</code>).</p><h2 id="catalog-admin" tabindex="-1">Catalog (admin) <a class="header-anchor" href="#catalog-admin" aria-label="Permalink to &quot;Catalog (admin)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Resource</th><th>Paths</th><th>Notes</th></tr></thead><tbody><tr><td>Modules</td><td>CRUD + restore/force</td><td>Full catalog admin. Fields include <code>uuid</code>, pricing (<code>monthly_price</code>, <code>yearly_price</code>, <code>currency</code>), <code>status</code>, <code>is_default_included</code>, <code>is_billable</code> — <strong>no</strong> payment-provider IDs</td></tr></tbody></table><p>Default-included modules (Leads, Tasks, Communication Templates) cannot be deleted while marked <code>is_default_included</code>. Modules with workspace subscriptions cannot be deleted until those subscriptions are removed.</p><p>Provider price mappings are managed under Payment Gateways (<code>GET/PUT /payment-gateways/{id}/module-prices</code>), not on Modules. Features catalog has been removed — modules are licensing products; Spatie permissions handle authorization.</p><h2 id="marketplace" tabindex="-1">Marketplace <a class="header-anchor" href="#marketplace" aria-label="Permalink to &quot;Marketplace&quot;">​</a></h2><p>Published modules only. Permission: <code>modules.list</code> / <code>modules.read</code>.</p><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/marketplace/modules</code></td><td>Paginated; filters: <code>search</code>, <code>category_id</code></td></tr><tr><td>GET</td><td><code>/marketplace/modules/{module}</code></td><td>Detail + <code>already_installed</code>, <code>required_modules</code>, <code>optional_modules</code>, <code>missing_required_modules</code>; optional <code>?tenant_id=</code></td></tr></tbody></table><p>Install for a workspace: <code>POST /tenants/{tenant}/modules</code> (not a separate marketplace purchase endpoint).</p><h2 id="module-subscriptions" tabindex="-1">Module subscriptions <a class="header-anchor" href="#module-subscriptions" aria-label="Permalink to &quot;Module subscriptions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Permission</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/module-subscriptions</code></td><td><code>module-subscriptions.list</code></td><td>Filters: <code>tenant_id</code>, <code>status</code>, <code>source</code></td></tr><tr><td>GET</td><td><code>/module-subscriptions/{module_subscription}</code></td><td><code>module-subscriptions.read</code></td><td>Includes <code>module</code>, <code>tenant</code>, <code>history</code></td></tr><tr><td>POST</td><td><code>/module-subscriptions/{module_subscription}/cancel</code></td><td><code>module-subscriptions.update</code></td><td>Purchased modules only; included modules rejected</td></tr><tr><td>POST</td><td><code>/module-subscriptions/{module_subscription}/deactivate</code></td><td><code>module-subscriptions.deactivate</code></td><td>Platform-admin suspend (works on included modules)</td></tr></tbody></table><h2 id="financial-ledger-read-only" tabindex="-1">Financial ledger (read-only) <a class="header-anchor" href="#financial-ledger-read-only" aria-label="Permalink to &quot;Financial ledger (read-only)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Permission</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/invoices</code></td><td><code>invoices.list</code></td><td>Platform-wide paginated list</td></tr><tr><td>GET</td><td><code>/invoices/{invoice}</code></td><td><code>invoices.read</code></td><td>Includes <code>tenant</code>, <code>items</code>, <code>payments</code></td></tr><tr><td>GET</td><td><code>/payments</code></td><td><code>payments.list</code></td><td>Platform-wide paginated list</td></tr><tr><td>GET</td><td><code>/payments/{payment}</code></td><td><code>payments.read</code></td><td>Includes <code>tenant</code>, <code>invoice</code>, <code>transactions</code></td></tr></tbody></table><p>Tenant-scoped lists: <code>GET /tenants/{tenant}/invoices</code>, <code>GET /tenants/{tenant}/payments</code>.</p><p>Invoices are created by the Billing Engine (consolidated run or purchase settlement) — no public write endpoints.</p><h2 id="payment-gateways" tabindex="-1">Payment gateways <a class="header-anchor" href="#payment-gateways" aria-label="Permalink to &quot;Payment gateways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Permission</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/payment-gateways</code></td><td><code>payment-gateways.list</code></td><td>List providers</td></tr><tr><td>GET</td><td><code>/payment-gateways/{id}</code></td><td><code>payment-gateways.read</code></td><td>Redacted config (secrets never returned)</td></tr><tr><td>POST</td><td><code>/payment-gateways/{id}/enable</code></td><td><code>payment-gateways.update</code></td><td></td></tr><tr><td>POST</td><td><code>/payment-gateways/{id}/disable</code></td><td><code>payment-gateways.update</code></td><td>Rejects if default</td></tr><tr><td>POST</td><td><code>/payment-gateways/{id}/default</code></td><td><code>payment-gateways.update</code></td><td>Syncs <code>default_payment_gateway</code> setting</td></tr><tr><td>PUT</td><td><code>/payment-gateways/{id}/config</code></td><td><code>payment-gateways.update</code></td><td>Merge encrypted credentials</td></tr><tr><td>PUT</td><td><code>/payment-gateways/{id}/mode</code></td><td><code>payment-gateways.update</code></td><td><code>sandbox</code> | <code>live</code></td></tr><tr><td>POST</td><td><code>/payment-gateways/{id}/test-connection</code></td><td><code>payment-gateways.update</code></td><td>Driver probe</td></tr><tr><td>GET</td><td><code>/payment-gateways/{id}/webhook-status</code></td><td><code>payment-gateways.read</code></td><td></td></tr><tr><td>GET</td><td><code>/payment-gateways/{id}/logs</code></td><td><code>payment-gateways.read</code></td><td>Operational logs</td></tr><tr><td>GET</td><td><code>/payment-gateways/{id}/webhook-logs</code></td><td><code>payment-gateways.read</code></td><td></td></tr><tr><td>GET</td><td><code>/payment-gateways/{id}/capabilities</code></td><td><code>payment-gateways.read</code></td><td>Capabilities + currencies + <code>requires_product_mapping</code></td></tr><tr><td>GET</td><td><code>/payment-gateways/{id}/module-prices</code></td><td><code>payment-gateways.read</code></td><td>Gateway ↔ module product/price mappings</td></tr><tr><td>PUT</td><td><code>/payment-gateways/{id}/module-prices</code></td><td><code>payment-gateways.update</code></td><td>Replace mappings (<code>{ mappings: [...] }</code>); 422 if gateway does not require mapping</td></tr></tbody></table><p>Also accepts <code>billing.manage</code> as an alternate permission.</p><h2 id="impersonation" tabindex="-1">Impersonation <a class="header-anchor" href="#impersonation" aria-label="Permalink to &quot;Impersonation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Permission</th><th>Notes</th></tr></thead><tbody><tr><td>POST</td><td><code>/tenants/{tenant}/impersonate</code></td><td><code>impersonation.start</code></td><td>Creates session; audits reason, IP, user-agent</td></tr><tr><td>POST</td><td><code>/impersonation/{impersonation}/end</code></td><td><code>impersonation.end</code> (or session owner)</td><td>Sets <code>ended_at</code>, <code>duration_seconds</code></td></tr></tbody></table><p>Returns session metadata only — tenant-app login token exchange is out of scope for Central v1.</p><h2 id="stripe-gateway-email-webhooks" tabindex="-1">Stripe / gateway / email webhooks <a class="header-anchor" href="#stripe-gateway-email-webhooks" aria-label="Permalink to &quot;Stripe / gateway / email webhooks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Notes</th></tr></thead><tbody><tr><td>POST</td><td><code>/stripe/webhook</code></td><td>Cashier-compatible path (<code>config(&#39;cashier.path&#39;)</code> + <code>/webhook</code>)</td></tr><tr><td>POST</td><td><code>/webhooks/gateways/{code}</code></td><td>Gateway-agnostic ingress for all drivers</td></tr><tr><td>POST</td><td><code>/webhooks/email/{provider}</code></td><td>Email delivery webhooks (Central)</td></tr><tr><td>POST</td><td><code>/webhooks/email/{provider}/{tenant}</code></td><td>Email delivery webhooks (Tenant custom mail)</td></tr></tbody></table><p><strong>Not</strong> under <code>/api/central/v1</code>. Payment paths normalize via <code>PaymentGatewayInterface::parseWebhook()</code> into <code>BillingEngine</code>. Email paths use <code>SupportsWebhooks</code> drivers. CSRF-exempt; rate-limited. Stripe Cashier route additionally syncs Cashier mirror tables.</p><h2 id="system" tabindex="-1">System <a class="header-anchor" href="#system" aria-label="Permalink to &quot;System&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/public/settings</code></td><td>Unauthenticated bootstrap (branding, formats, registration/maintenance flags). No secrets.</td></tr><tr><td>POST</td><td><code>/public/register-workspace</code></td><td>Self-service workspace create when <code>registration_enabled</code>; otherwise <code>403</code> with dedicated message</td></tr><tr><td>GET</td><td><code>/system-settings</code></td><td>All admin settings (secrets masked). Response <code>meta.mail_webhook</code> includes webhook URL + event catalog when the active provider supports webhooks.</td></tr><tr><td>PUT</td><td><code>/system-settings</code></td><td><code>{ &quot;settings&quot;: { &quot;key&quot;: value } }</code> — per-key validation; may include <code>mail_webhook_events</code> / <code>mail_webhook_secret</code></td></tr><tr><td>POST</td><td><code>/system-settings/test-mail</code></td><td><code>{ &quot;email&quot;: &quot;…&quot; }</code> — sends test mail using runtime SMTP config</td></tr><tr><td>POST</td><td><code>/system-settings/branding/{logo|favicon}</code></td><td>Multipart <code>file</code> upload → stores via <code>FileUploadService</code> on the configured uploads disk</td></tr><tr><td>GET</td><td><code>/email-logs</code></td><td>Paginated delivery logs (<code>has_body</code>; bodies omitted)</td></tr><tr><td>GET</td><td><code>/email-logs/{uuid}</code></td><td>Log detail including <code>body_html</code> / <code>body_text</code></td></tr><tr><td>POST</td><td><code>/email-logs/{uuid}/resend</code></td><td>Resend from stored body (<code>email-logs.resend</code>, throttle 6/min)</td></tr></tbody></table><p>Settings groups: <code>general</code>, <code>localization</code>, <code>mail</code>, <code>branding</code>, <code>security</code>, <code>maintenance</code>, <code>billing</code>.</p><h3 id="consumed-keys" tabindex="-1">Consumed keys <a class="header-anchor" href="#consumed-keys" aria-label="Permalink to &quot;Consumed keys&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Group</th><th>Keys</th><th>Runtime use</th></tr></thead><tbody><tr><td>general</td><td><code>app_name</code>, <code>company_name</code>, <code>timezone</code>, <code>locale</code>, <code>currency</code>, <code>registration_enabled</code></td><td>App title/config, tenant defaults, self-service registration</td></tr><tr><td>localization</td><td><code>date_format</code>, <code>time_format</code></td><td>Central SPA formatters</td></tr><tr><td>mail</td><td><code>mail_provider</code>, SMTP / Postmark / Mailgun credentials, <code>mail_webhook_secret</code>, <code>mail_webhook_events</code>, From identity</td><td>Laravel mail + delivery webhooks</td></tr><tr><td>branding</td><td><code>button_color</code>, <code>support_email</code>, <code>logo_path</code>, <code>favicon_path</code></td><td>SPA CSS/<code>document.title</code>/sidebar; support footer on tenant-facing emails</td></tr><tr><td>security</td><td><code>session_lifetime_minutes</code>, <code>password_min_length</code>, <code>password_require_special</code></td><td>Session lifetime; centralized <code>PasswordRule</code> / <code>Password::defaults()</code></td></tr><tr><td>maintenance</td><td><code>maintenance_mode</code>, <code>maintenance_message</code>, <code>maintenance_eta</code></td><td><strong>Tenant Application only</strong> (<code>tenant.available</code> middleware). Central stays up.</td></tr><tr><td>billing</td><td><code>invoice_prefix</code>, <code>proration_mode</code>, <code>default_payment_gateway</code>, <code>trial_enabled</code>, <code>stripe_enabled</code>, <code>stripe_webhook_configured</code></td><td>Billing engine / invoices</td></tr></tbody></table><p>Removed: <code>primary_color</code>, <code>feature_registration</code>, <code>feature_invites</code>, <code>queue_connection_display</code>, <code>filesystem_disk</code>.</p><h2 id="dashboard-payload" tabindex="-1">Dashboard payload <a class="header-anchor" href="#dashboard-payload" aria-label="Permalink to &quot;Dashboard payload&quot;">​</a></h2><p><code>GET /dashboard</code> returns workspace stats, module subscription status counts, revenue (MRR from billable active subscriptions), growth series, recent tenants, recent module subscriptions, recent activities.</p><p>Series shapes (frontend contract):</p><ul><li><code>growth[]</code>: <code>{ month: &quot;YYYY-MM&quot;, count: number }</code></li><li><code>revenue_series[]</code>: <code>{ month: &quot;YYYY-MM&quot;, amount: number }</code> (zeros until paid modules exist)</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Seeded by <code>Database\\Seeders\\Central\\PermissionsSeeder</code>, guard <code>central-api</code>.</p><table tabindex="0"><thead><tr><th>Group</th><th>Permissions</th></tr></thead><tbody><tr><td><code>users</code></td><td><code>list</code>, <code>create</code>, <code>read</code>, <code>update</code>, <code>delete</code>, <code>restore</code>, <code>force.delete</code>, <code>suspend</code>, <code>unsuspend</code>, <code>invite</code>, <code>reset-password</code></td></tr><tr><td><code>tenants</code></td><td><code>list</code>, <code>create</code>, <code>read</code>, <code>update</code>, <code>delete</code>, <code>restore</code>, <code>force.delete</code>, <code>archive</code></td></tr><tr><td><code>roles</code></td><td><code>list</code>, <code>create</code>, <code>read</code>, <code>update</code>, <code>delete</code>, <code>clone</code></td></tr><tr><td><code>dashboard</code></td><td><code>view</code></td></tr><tr><td><code>billing</code></td><td><code>manage</code></td></tr><tr><td><code>modules</code></td><td><code>list</code>, <code>create</code>, <code>read</code>, <code>update</code>, <code>delete</code>, <code>restore</code>, <code>force.delete</code></td></tr><tr><td><code>module-subscriptions</code></td><td><code>list</code>, <code>create</code>, <code>read</code>, <code>update</code>, <code>delete</code>, <code>deactivate</code></td></tr><tr><td><code>invoices</code></td><td><code>list</code>, <code>read</code>, <code>update</code></td></tr><tr><td><code>payments</code></td><td><code>list</code>, <code>read</code>, <code>update</code></td></tr><tr><td><code>impersonation</code></td><td><code>start</code>, <code>end</code>, <code>list</code></td></tr><tr><td><code>system-settings</code></td><td><code>list</code>, <code>update</code></td></tr></tbody></table><h2 id="removed" tabindex="-1">Removed <a class="header-anchor" href="#removed" aria-label="Permalink to &quot;Removed&quot;">​</a></h2><ul><li><code>/features</code> (+ restore/force)</li><li><code>/plans</code>, <code>/plans/{plan}/modules|features|limits</code></li><li><code>/limit-definitions</code></li><li><code>/tenant-subscriptions</code> (+ cancel/resume/suspend)</li><li><code>/subscriptions</code>, <code>/setting-definitions</code></li></ul><h2 id="artisan" tabindex="-1">Artisan <a class="header-anchor" href="#artisan" aria-label="Permalink to &quot;Artisan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Notes</th></tr></thead><tbody><tr><td><code>billing:run-consolidated</code></td><td>Daily scheduled; invoices all due workspaces</td></tr></tbody></table><p>Postman: <code>SaaS-Backend/.docs/postman/Central.postman_collection.json</code> (refresh after API changes).</p>',61)])])}const m=t(c,[["render",s]]);export{u as __pageData,m as default};
